def palindromePairs(words):
    res = []
    word_dict = {w: i for i, w in enumerate(words)}
    for i, w in enumerate(words):
        for j in range(len(w) + 1):
            prefix, suffix = w[:j], w[j:]
            if prefix == prefix[::-1] and suffix[::-1] != w and suffix[::-1] in word_dict:
                res.append([word_dict[suffix[::-1]], i])
            if j != len(w) and suffix == suffix[::-1] and prefix[::-1] != w and prefix[::-1] in word_dict:
                res.append([i, word_dict[prefix[::-1]]])
    return res

